import{_ as e,o as n,c as r,e as o}from"./app-cb4a12e2.js";const a={};function i(s,t){return n(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="ai-agent-项目经验-面试表达指南" tabindex="-1"><a class="header-anchor" href="#ai-agent-项目经验-面试表达指南" aria-hidden="true">#</a> AI Agent 项目经验 - 面试表达指南</h1><h2 id="_1-项目一句话介绍-elevator-pitch" tabindex="-1"><a class="header-anchor" href="#_1-项目一句话介绍-elevator-pitch" aria-hidden="true">#</a> 1. 项目一句话介绍 (Elevator Pitch)</h2><blockquote><p><strong>面试官：</strong> 请介绍一下你最近做的 AI 项目。</p></blockquote><p><strong>回答：</strong> “我参与核心开发的 <strong>Coco App</strong>，是一个<strong>企业级的智能搜索与 AI Agent 平台</strong>。 它不仅仅是一个对话机器人，而是基于 <strong>RAG（检索增强生成）</strong> 和 <strong>MCP（模型上下文协议）</strong> 构建的生产力工具。 它能够连接企业内部的各种数据源（如 GitHub, Notion, 数据库），具备<strong>深度研究 (Deep Research)</strong> 能力，可以自主拆解任务、调用工具并生成结构化的研究报告。”</p><hr><h2 id="_2-核心职责与技术亮点-key-responsibilities" tabindex="-1"><a class="header-anchor" href="#_2-核心职责与技术亮点-key-responsibilities" aria-hidden="true">#</a> 2. 核心职责与技术亮点 (Key Responsibilities)</h2><blockquote><p><strong>面试官：</strong> 你在这个项目中主要负责什么？用到了哪些关键技术？</p></blockquote><p><strong>回答：</strong> “我主要负责 <strong>Agent 前端交互架构的设计与实现</strong>，以及 <strong>Tauri 桌面端与 Rust 后端的深度集成</strong>。核心技术亮点包括：”</p><h3 id="a-复杂流式交互设计-frontend-interaction" tabindex="-1"><a class="header-anchor" href="#a-复杂流式交互设计-frontend-interaction" aria-hidden="true">#</a> A. 复杂流式交互设计 (Frontend Interaction)</h3><ul><li><strong>挑战</strong>：Agent 的响应不是简单的文本流，而是包含了“思考过程 (CoT)”、“工具调用 (Tool Calls)”、“引用来源 (Citations)”等多维信息的混合流。</li><li><strong>解决方案</strong>： <ul><li>我设计了一套<strong>基于 SSE (Server-Sent Events) 的流式解析器</strong>，能够实时拆分并处理 <code>thought</code>（思维链）、<code>tool_call</code>（工具状态）和 <code>content</code>（最终内容）。</li><li>实现了 <strong>增量渲染引擎</strong>，让用户能实时看到 Agent 的“思考步骤”（如 <code>&lt;Think /&gt;</code> 组件）和“行动轨迹”（如正在搜索数据库...），极大地提升了用户对 AI 的信任感和容忍度。</li></ul></li></ul><h3 id="b-模型上下文协议-mcp-集成" tabindex="-1"><a class="header-anchor" href="#b-模型上下文协议-mcp-集成" aria-hidden="true">#</a> B. 模型上下文协议 (MCP) 集成</h3><ul><li><strong>挑战</strong>：传统的 Agent 对接外部工具需要写大量胶水代码，扩展性差。</li><li><strong>解决方案</strong>： <ul><li>我们在项目中落地了 <strong>MCP (Model Context Protocol)</strong> 标准。</li><li>我在前端实现了 <strong>MCP 管理界面</strong>，允许用户动态挂载/卸载数据源。</li><li>通过标准化接口，Agent 可以自动发现并调用本地或远程的工具（如计算器、文件搜索），实现了工具生态的解耦。</li></ul></li></ul><h3 id="c-跨平台混合架构-hybrid-architecture" tabindex="-1"><a class="header-anchor" href="#c-跨平台混合架构-hybrid-architecture" aria-hidden="true">#</a> C. 跨平台混合架构 (Hybrid Architecture)</h3><ul><li><strong>挑战</strong>：需要在桌面端提供高性能的本地能力（如读取本地文件索引）。</li><li><strong>解决方案</strong>： <ul><li>采用 <strong>React + Tauri (Rust)</strong> 架构。前端负责 UI 状态管理，Rust 层作为系统桥梁。</li><li>我封装了 <code>useChatActions</code> Hook，管理 Agent 的多阶段推理状态（意图识别 -&gt; 工具选择 -&gt; 数据获取），确保了前后端状态的严格同步。</li></ul></li></ul><hr><h2 id="_3-针对性面试问答-q-a-scenarios" tabindex="-1"><a class="header-anchor" href="#_3-针对性面试问答-q-a-scenarios" aria-hidden="true">#</a> 3. 针对性面试问答 (Q&amp;A Scenarios)</h2><h3 id="q1-你们的-agent-是如何解决-幻觉-问题的" tabindex="-1"><a class="header-anchor" href="#q1-你们的-agent-是如何解决-幻觉-问题的" aria-hidden="true">#</a> Q1: 你们的 Agent 是如何解决“幻觉”问题的？</h3><p><strong>回答：</strong> “我们主要通过 <strong>RAG (检索增强生成)</strong> 和 <strong>引用溯源</strong> 来解决。 在技术实现上，当 Agent 生成回答时，会携带引用的元数据。我在前端开发了 <code>&lt;Citation /&gt;</code> 组件，会在回答的对应位置高亮显示引用来源（如‘参见文档 A 第 3 页’），用户点击即可跳转查看原始数据。这让 AI 的回答变得‘有据可查’。”</p><h3 id="q2-如何优化-agent-的响应速度体验" tabindex="-1"><a class="header-anchor" href="#q2-如何优化-agent-的响应速度体验" aria-hidden="true">#</a> Q2: 如何优化 Agent 的响应速度体验？</h3><p><strong>回答：</strong> “大模型的推理确实有延迟，特别是开启深度思考模式时。我的优化策略是：</p><ol><li><strong>极致的流式渲染</strong>：不等待完整句子，按字符级 (Token) 更新 UI。</li><li><strong>可视化推理过程</strong>：通过将 Agent 的 <code>loadingStep</code>（如正在分析意图、正在调用工具）可视化，把‘等待时间’转化为‘用户阅读 AI 思考过程的时间’，心理上降低了等待焦虑。”</li></ol><h3 id="q3-你们的前端架构是如何支持多种-agent-形态的" tabindex="-1"><a class="header-anchor" href="#q3-你们的前端架构是如何支持多种-agent-形态的" aria-hidden="true">#</a> Q3: 你们的前端架构是如何支持多种 Agent 形态的？</h3><p><strong>回答：</strong> “我们采用了 <strong>Monorepo</strong> 策略，将核心聊天能力抽离为 <code>@infinilabs/ai-chat</code> 和 <code>@infinilabs/chat-message</code> 独立包。 这样我们的一套核心代码，既能构建出类似 Perplexity 的<strong>全屏深度搜索版</strong>，也能构建出嵌入在 IDE 或业务系统右下角的 <strong>Copilot 悬浮窗版</strong>，实现了最大程度的代码复用。”</p><hr><h2 id="_4-总结升华-closing" tabindex="-1"><a class="header-anchor" href="#_4-总结升华-closing" aria-hidden="true">#</a> 4. 总结升华 (Closing)</h2><p>“通过 Coco 项目，我不仅仅掌握了 LLM API 的调用，更重要的是深入理解了 <strong>AI Native 应用的交互范式</strong>——即如何通过结构化的 UI（如思维链、工具卡片）来弥补大模型的黑盒特性，以及如何通过标准协议（如 MCP）来构建可扩展的 Agent 生态。”</p>',26)])])}const l=e(a,[["render",i],["__file","AI_Agent_Interview_Prep.html.vue"]]);export{l as default};
